    // === 3. ФУНКЦИЯ ДОБАВЛЕНИЯ КНОПОК ===

    function addButtons() {
        // Проверяем, включена ли настройка
        if (Lampa.Storage.field('Reloadbutton') !== true) {
            hideButtons();
            return;
        }

        // Удаляем старые кнопки
        $('#RELOAD_BTN').remove();
        $('#CONSOLE_BTN').remove();
        $('#EXIT_BTN').remove();
        $('#CLEARCACHE_BTN').remove();

        // Находим контейнер для кнопок
        const container = $('.head__actions');
        if (container.length === 0) return;

        // Создаем кнопки с уникальными ID
        const buttons = [
            { id: 'RELOAD_BTN', icon: ICONS.reload, tooltip: 'reload_button', action: reloadAction },
            { id: 'CONSOLE_BTN', icon: ICONS.console, tooltip: 'console_button', action: consoleAction },
            { id: 'EXIT_BTN', icon: ICONS.exit, tooltip: 'exit_button', action: exitAction },
            { id: 'CLEARCACHE_BTN', icon: ICONS.clearCache, tooltip: 'clear_cache_button', action: clearCacheAction }
        ];

        buttons.forEach(btn => {
            const html = `
                <div id="${btn.id}" class="head__action selector" 
                     style="display:flex;align-items:center;justify-content:center;padding:0 0.5em;cursor:pointer;"
                     title="${Lampa.Lang.translate(btn.tooltip)}">
                    ${btn.icon}
                </div>
            `;
            const element = $(html);
            container.append(element);
            
            // Обработчики событий для TV пультов
            element.on('hover:enter hover:click hover:touch', function(e) {
                e.preventDefault();
                btn.action();
            });

            // Эффект при наведении
            element.on('hover:enter', function() {
                $(this).css('opacity', '0.7');
            });
            element.on('hover:leave', function() {
                $(this).css('opacity', '1');
            });
        });

        // Добавляем разделитель, если его нет
        if (!$('.head__actions .separator').length) {
            $('.head__actions').prepend('<span class="separator" style="width:1px;height:24px;background:rgba(255,255,255,0.2);margin:0 0.5em;"></span>');
        }
    }

    // === 4. ФУНКЦИИ ДЕЙСТВИЙ ===

    // Перезагрузка
    function reloadAction() {
        location.reload();
    }

    // Консоль
    function consoleAction() {
        try {
            if (typeof Lampa !== 'undefined' && Lampa.Controller) {
                Lampa.Controller.toggle('console');
            } else {
                // Альтернатива - показать консоль если она есть
                const consoleEl = $('#console');
                if (consoleEl.length) {
                    consoleEl.toggleClass('hide');
                } else {
                    console.log('Консоль вызвана');
                }
            }
        } catch(e) {
            console.log('Ошибка открытия консоли:', e);
        }
    }

    // Выход из приложения
    function exitAction() {
        try {
            // Пробуем выйти разными способами
            
            // 1. Через Lampa Activity
            if (typeof Lampa !== 'undefined' && Lampa.Activity) {
                Lampa.Activity.out();
            }

            // 2. Tizen (Samsung Smart TV)
            if (typeof tizen !== 'undefined' && tizen.application) {
                tizen.application.getCurrentApplication().exit();
                return;
            }

            // 3. webOS (LG Smart TV)
            if (typeof webOS !== 'undefined') {
                window.close();
                return;
            }

            // 4. Android TV
            if (typeof Lampa !== 'undefined' && Lampa.Android) {
                Lampa.Android.exit();
                return;
            }

            // 5. Apple TV
            if (Lampa.Platform && Lampa.Platform.is('apple_tv')) {
                window.location.assign('exit://exit');
                return;
            }

            // 6. NW.js (десктоп)
            if (typeof nw !== 'undefined' && nw.Window) {
                nw.Window.get().close();
                return;
            }

            // 7. Orsay (старые Smart TV)
            if (typeof Lampa !== 'undefined' && Lampa.Orsay) {
                Lampa.Orsay.exit();
                return;
            }

            // 8. Fallback - закрыть окно
            if (window.close) {
                window.close();
            } else {
                Lampa.Noty.show('Выход не поддерживается на этой платформе');
            }
        } catch(err) {
            console.warn('Ошибка при выходе:', err);
            try { window.close(); } catch(e) {}
        }
    }

    // Очистка кэша
    function clearCacheAction() {
        const btn = $('#CLEARCACHE_BTN');
        btn.addClass('loading');

        try {
            // Метод 1: Через Lampa.Cache
            if (Lampa && Lampa.Cache && typeof Lampa.Cache.clear === 'function') {
                Lampa.Cache.clear();
                setTimeout(() => {
                    Lampa.Noty.show('🗑 Кеш Lampa очищено');
                    btn.removeClass('loading');
                    setTimeout(() => location.reload(), 500);
                }, 800);
                return;
            }

            // Метод 2: Очистка localStorage вручную
            setTimeout(() => {
                let removed = 0;
                const keysToRemove = [];
                
                for (let i = 0; i < localStorage.length; i++) {
                    const key = localStorage.key(i);
                    if (key && (
                        key.startsWith('card_') || 
                        key.startsWith('full_card_') || 
                        key.startsWith('lite_card_') || 
                        key.startsWith('viewed_card_') || 
                        key.startsWith('viewed_continue_') || 
                        key.startsWith('parser_') || 
                        key.startsWith('cub_') || 
                        key.startsWith('start_time_') || 
                        key.startsWith('cache_') ||
                        key.startsWith('search_') ||
                        key.startsWith('catalog_')
                    )) {
                        keysToRemove.push(key);
                    }
                }
                
                keysToRemove.forEach(key => {
                    localStorage.removeItem(key);
                    removed++;
                });
                
                Lampa.Noty.show(`🗑 Кэш очищен: ${removed} ключей`);
                btn.removeClass('loading');
                setTimeout(() => location.reload(), 500);
            }, 500);

        } catch(e) {
            console.error('Ошибка очистки кэша:', e);
            Lampa.Noty.show('Ошибка очистки кэша');
            btn.removeClass('loading');
        }
    }

    // === 5. ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ===

    function hideButtons() {
        $('#RELOAD_BTN').hide();
        $('#CONSOLE_BTN').hide();
        $('#EXIT_BTN').hide();
        $('#CLEARCACHE_BTN').hide();
    }

    // Добавляем CSS стили
    function addStyles() {
        if (document.getElementById('reloadbutton-styles')) return;
        
        const css = `
            #RELOAD_BTN, #CONSOLE_BTN, #EXIT_BTN, #CLEARCACHE_BTN {
                transition: all 0.2s ease;
            }
            #RELOAD_BTN:hover, #CONSOLE_BTN:hover, #EXIT_BTN:hover, #CLEARCACHE_BTN:hover {
                transform: scale(1.1);
            }
            #RELOAD_BTN.loading, #CONSOLE_BTN.loading, #EXIT_BTN.loading, #CLEARCACHE_BTN.loading {
                animation: pulse 0.5s ease infinite alternate;
            }
            @keyframes pulse {
                0% { opacity: 1; }
                100% { opacity: 0.3; }
            }
            #CLEARCACHE_BTN svg path {
                fill: lime !important;
                transition: fill 0.2s ease;
            }
            #CLEARCACHE_BTN:hover svg path {
                fill: #00ff00 !important;
            }
            #RELOAD_BTN svg path {
                stroke: #4fc3f7 !important;
            }
            #CONSOLE_BTN svg path {
                stroke: #ffb74d !important;
            }
            #EXIT_BTN svg path {
                fill: #ef5350 !important;
            }
        `;
        
        const style = document.createElement('style');
        style.id = 'reloadbutton-styles';
        style.textContent = css;
        document.head.appendChild(style);
    }

